  ('customs-7fec267e-moex-00052', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '當政府支出增加時，通常會透過下列何者產生所謂的排擠效果（crowding-outeffect）？', '["所得上升", "所得下降", "利率上升", "利率下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00053', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '有關乘數效果（multipliereffect），下列敘述何者正確？', '["不管政府是增稅還是減稅，都會有乘數效果", "不管政府是增稅還是減稅，都不會有乘數效果", "只有減稅會有乘數效果，增稅則否", "只有增稅會有乘數效果，減稅則否"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
